4. src/lib/schemas/auth.schema.ts (Zod v4):
   export const loginSchema = z.object({ email: z.string().email('올바른 이메일을 입력하세요'), password: z.string().min(8, '비밀번호는 8자 이상') })
   export const signupSchema = z.object({ email: z.string().email(), name: z.string().min(1), password: z.string().min(8), confirmPassword: z.string() }).refine(data => data.password === data.confirmPassword, { message: '비밀번호가 일치하지 않습니다', path: ['confirmPassword'] })
   export type LoginSchema = z.infer<typeof loginSchema>
   export type SignupSchema = z.infer<typeof signupSchema>

5. src/lib/schemas/invoice.schema.ts:
   export const invoiceItemSchema = z.object({ name: z.string().min(1), quantity: z.number().positive(), unitPrice: z.number().nonnegative(), notionPageId: z.string().optional() })
   export const invoiceCreateSchema = z.object({ clientName: z.string().min(1), clientContact: z.string().min(1), validUntil: z.string(), items: z.array(invoiceItemSchema).min(1, '최소 1개 항목 필요') })

6. supabase/migrations/001_create_tables.sql:
   CREATE TABLE users (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), email TEXT UNIQUE NOT NULL, name TEXT NOT NULL, notion_access_token TEXT, created_at TIMESTAMPTZ DEFAULT NOW())
   CREATE TABLE invoices (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), user_id UUID REFERENCES users(id) ON DELETE CASCADE, client_name TEXT NOT NULL, client_contact TEXT NOT NULL, valid_until DATE NOT NULL, total_amount NUMERIC(15,2) NOT NULL DEFAULT 0, share_token TEXT UNIQUE, token_expires_at TIMESTAMPTZ, created_at TIMESTAMPTZ DEFAULT NOW())
   CREATE TABLE invoice_items (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), invoice_id UUID REFERENCES invoices(id) ON DELETE CASCADE, name TEXT NOT NULL, quantity NUMERIC(10,2) NOT NULL, unit_price NUMERIC(15,2) NOT NULL, notion_page_id TEXT, created_at TIMESTAMPTZ DEFAULT NOW())

7. supabase/migrations/002_rls_policies.sql:
   ALTER TABLE invoices ENABLE ROW LEVEL SECURITY
   CREATE POLICY owner_all ON invoices FOR ALL USING (auth.uid() = user_id)
   CREATE POLICY public_read_by_token ON invoices FOR SELECT USING (share_token IS NOT NULL AND token_expires_at > NOW())
   ALTER TABLE invoice_items ENABLE ROW LEVEL SECURITY
   CREATE POLICY owner_all ON invoice_items FOR ALL USING (invoice_id IN (SELECT id FROM invoices WHERE user_id = auth.uid()))
   CREATE POLICY public_read_by_invoice ON invoice_items FOR SELECT USING (invoice_id IN (SELECT id FROM invoices WHERE share_token IS NOT NULL AND token_expires_at > NOW()))

