   import { createServerClient } from '@supabase/ssr'
   import { cookies } from 'next/headers'
   export async function createClient() {
     const cookieStore = await cookies()
     return createServerClient(url, anonKey, { cookies: { getAll: () => cookieStore.getAll(), setAll: (cs) => cs.forEach(({ name, value, options }) => cookieStore.set(name, value, options)) } })
   }

4. src/lib/supabase/middleware.ts (미들웨어용):
   import { createServerClient } from '@supabase/ssr'
   export function createClient(request: NextRequest, response: NextResponse) {
     return createServerClient(url, anonKey, { cookies: { getAll: () => request.cookies.getAll(), setAll: (cs) => cs.forEach(({ name, value, options }) => { request.cookies.set(name, value); response.cookies.set(name, value, options) }) } })
   }

5. src/middleware.ts 완성:
   import { createClient } from '@/lib/supabase/middleware'
   export async function middleware(request: NextRequest) {
     const response = NextResponse.next({ request })
     const supabase = createClient(request, response)
     const { data: { user } } = await supabase.auth.getUser()
     const { pathname } = request.nextUrl
     const isProtected = pathname.startsWith('/dashboard') || pathname.startsWith('/invoices')
     const isAuthPage = pathname.startsWith('/login') || pathname.startsWith('/signup')
     if (isProtected && !user) return NextResponse.redirect(new URL('/login', request.url))
     if (isAuthPage && user) return NextResponse.redirect(new URL('/dashboard', request.url))
     return response
   }
   export const config = { matcher: ['/((?!_next/static|_next/image|favicon.ico|.*\.(?:svg|png|jpg|jpeg|gif|webp)$).*)'] }

6. src/app/(protected)/layout.tsx 완성:
   import { redirect } from 'next/navigation'
   import { createClient } from '@/lib/supabase/server'
   export default async function ProtectedLayout({ children }: { children: React.ReactNode }) {
     const supabase = await createClient()
     const { data: { user } } = await supabase.auth.getUser()
     if (!user) redirect('/login')
     return <>{children}</>
   }
